const SOURCE_BASE_URL = 'https://api-comexstat.mdic.gov.br';
const HISTORY_MONTHS = 6;
const PREVIOUS_YEAR_TAIL_FROM_MONTH = 7; // Jul-Dec of previous year to bridge cross-year monthDetail bug.
const updated = $json && $json.data ? $json.data : {};
const latestYear = Number(updated.year);
const latestMonth = Number(updated.monthNumber);

if (!Number.isInteger(latestYear) || !Number.isInteger(latestMonth) || latestMonth < 1 || latestMonth > 12) {
  throw new Error('Comex Stat updated endpoint returned invalid year/month');
}

function pad(value) {
  return String(value).padStart(2, '0');
}

function shiftPeriod(year, month, offsetMonths) {
  const date = new Date(Date.UTC(year, month - 1 + offsetMonths, 1));
  return {
    year: date.getUTCFullYear(),
    month: date.getUTCMonth() + 1,
    period: date.getUTCFullYear() + '-' + pad(date.getUTCMonth() + 1),
  };
}

function buildRequest(details, from, to, ncmCodes) {
  return {
    flow: 'export',
    monthDetail: true,
    period: { from, to },
    filters: [
      {
        filter: 'ncm',
        values: ncmCodes,
      },
    ],
    details,
    metrics: ['metricFOB', 'metricKG', 'metricStatistic'],
  };
}

const latestPeriod = shiftPeriod(latestYear, latestMonth, 0);
const previousPeriod = shiftPeriod(latestYear, latestMonth, -1);
const sameMonthPreviousYear = shiftPeriod(latestYear, latestMonth, -12);
const sixMonthStartPeriod = shiftPeriod(latestYear, latestMonth, -(HISTORY_MONTHS - 1));

const currentYearFromMonth = Math.max(1, latestMonth - (HISTORY_MONTHS - 1));
const currentYearFromPeriod = latestYear + '-' + pad(currentYearFromMonth);
const previousYear = latestYear - 1;
const previousYearTailFromPeriod = previousYear + '-' + pad(PREVIOUS_YEAR_TAIL_FROM_MONTH);
const previousYearTailToPeriod = previousYear + '-12';

const ncmGroups = {
  green: ['09011110', '09011190', '09011200'],
  roasted: ['09012100', '09012200'],
  soluble: ['21011110', '21011190', '21011200'],
};
const ncmCodes = [
  ...ncmGroups.green,
  ...ncmGroups.roasted,
  ...ncmGroups.soluble,
];

const stateCountryCurrentRequest = buildRequest(
  ['state', 'country', 'ncm'],
  currentYearFromPeriod,
  latestPeriod.period,
  ncmCodes,
);

const stateCountryPreviousRequest = buildRequest(
  ['state', 'country', 'ncm'],
  previousYearTailFromPeriod,
  previousYearTailToPeriod,
  ncmCodes,
);

const transportCurrentRequest = buildRequest(
  ['via', 'ncm'],
  currentYearFromPeriod,
  latestPeriod.period,
  ncmCodes,
);

const transportPreviousRequest = buildRequest(
  ['via', 'ncm'],
  previousYearTailFromPeriod,
  previousYearTailToPeriod,
  ncmCodes,
);

return [{
  json: {
    source: 'COMEX_STAT',
    source_format: 'json_api',
    source_base_url: SOURCE_BASE_URL,
    source_url: SOURCE_BASE_URL + '/general?language=pt',
    source_updated_date: updated.updated || null,
    latest_available_year: latestPeriod.year,
    latest_available_month: latestPeriod.month,
    latest_available_period: latestPeriod.period,
    previous_period: previousPeriod.period,
    same_month_previous_year: sameMonthPreviousYear.period,
    lookback_months: HISTORY_MONTHS,
    requested_lookback_months: HISTORY_MONTHS,
    period_from: sixMonthStartPeriod.period,
    period_to: latestPeriod.period,
    state_country_windows: {
      previous_year_tail: { from: previousYearTailFromPeriod, to: previousYearTailToPeriod },
      current_year: { from: currentYearFromPeriod, to: latestPeriod.period },
    },
    transport_windows: {
      previous_year_tail: { from: previousYearTailFromPeriod, to: previousYearTailToPeriod },
      current_year: { from: currentYearFromPeriod, to: latestPeriod.period },
    },
    ncm_groups: ncmGroups,
    ncm_codes: ncmCodes,
    state_country_current_request: stateCountryCurrentRequest,
    state_country_previous_request: stateCountryPreviousRequest,
    transport_current_request: transportCurrentRequest,
    transport_previous_request: transportPreviousRequest,
    // Backward-compatible aliases used in previous parser versions.
    state_series_request: stateCountryCurrentRequest,
    destination_series_request: stateCountryCurrentRequest,
    transport_series_request: transportCurrentRequest,
  },
}];

function getCollectedPeriod(isoTs, cadenza) {
  const d = new Date(isoTs || new Date().toISOString());
  const pad = n => String(n).padStart(2, '0');
  const yyyy = d.getUTCFullYear();
  const mm = pad(d.getUTCMonth() + 1);
  const dd = pad(d.getUTCDate());
  const hh = pad(d.getUTCHours());
  const doy = Math.floor((d - new Date(Date.UTC(yyyy,0,1))) / 86400000);
  const week = pad(Math.ceil((doy + new Date(Date.UTC(yyyy,0,1)).getUTCDay() + 1) / 7));
  switch((cadenza||'').toLowerCase()) {
    case 'hourly':  return `${yyyy}-${mm}-${dd}T${hh}`;
    case 'daily':   return `${yyyy}-${mm}-${dd}`;
    case 'weekly':  return `${yyyy}-W${week}`;
    case 'monthly': return `${yyyy}-${mm}`;
    default:        return `${yyyy}-${mm}-${dd}`;
  }
}
const now = new Date().toISOString();
const _collectedPeriod = getCollectedPeriod(now, 'monthly');
const expectedFreshnessHours = 24 * 35;
const isFresh = (new Date() - new Date(now)) / 3600000 < expectedFreshnessHours;

const meta = $('Comex Build Query Params').item.json;
const updatedResponse = $('Comex Updated Check').item.json;

function getNodeJson(nodeName) {
  try {
    return $(nodeName).item.json;
  } catch (e) {
    return null;
  }
}

const stateResponses = [
  getNodeJson('Comex Fetch State Series Previous Tail'),
  getNodeJson('Comex Fetch State Series Window'),
].filter(Boolean);

const transportResponses = [
  getNodeJson('Comex Port Snapshot Previous Tail'),
  getNodeJson('Comex Port Snapshot'),
].filter(Boolean);

const GREEN_CODES = new Set(meta.ncm_groups.green);
const ROASTED_CODES = new Set(meta.ncm_groups.roasted);
const SOLUBLE_CODES = new Set(meta.ncm_groups.soluble);
const LOOKBACK_MONTHS = Math.max(1, Number(meta.lookback_months || 6));

function round(value, decimals = 4) {
  if (value === null || value === undefined || Number.isNaN(value)) return null;
  return Number(Number(value).toFixed(decimals));
}

function pad(value) {
  return String(value).padStart(2, '0');
}

function shiftPeriod(period, offsetMonths) {
  const match = String(period || '').match(/^(\d{4})-(\d{2})$/);
  if (!match) return null;
  const year = Number(match[1]);
  const month = Number(match[2]);
  const date = new Date(Date.UTC(year, month - 1 + offsetMonths, 1));
  return date.getUTCFullYear() + '-' + pad(date.getUTCMonth() + 1);
}

function extractRows(payload) {
  if (Array.isArray(payload)) return payload;
  if (payload && payload.data && Array.isArray(payload.data.list)) return payload.data.list;
  if (payload && payload.data && Array.isArray(payload.data)) return payload.data;
  if (payload && Array.isArray(payload.list)) return payload.list;
  return [];
}

function normalizeText(value) {
  return String(value ?? '').trim();
}

function normalizeStateKey(value) {
  return normalizeText(value)
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase();
}

function toNumber(value, decimals = 4) {
  if (value === null || value === undefined || value === '') return null;
  if (typeof value === 'number') return Number.isFinite(value) ? round(value, decimals) : null;
  const raw = normalizeText(value);
  if (!raw) return null;
  const cleaned = raw.includes(',')
    ? raw.replace(/\./g, '').replace(',', '.')
    : raw;
  const numeric = Number(cleaned);
  return Number.isNaN(numeric) ? null : round(numeric, decimals);
}

function pctChange(current, previous, decimals = 4) {
  if (current === null || previous === null || previous === 0) return null;
  return round(((current - previous) / previous) * 100, decimals);
}

function sharePct(part, total, decimals = 4) {
  if (part === null || total === null || total === 0) return null;
  return round((part / total) * 100, decimals);
}

function sharePpChange(current, previous, decimals = 4) {
  if (current === null || previous === null) return null;
  return round(current - previous, decimals);
}

function formatNumber(value, decimals = 2) {
  return value === null ? 'n/a' : Number(value).toFixed(decimals);
}

function extractNcmCode(value) {
  const raw = normalizeText(value);
  if (!raw) return null;
  const match = raw.match(/\b(\d{8})\b/);
  if (match) return match[1];
  const digits = raw.replace(/\D/g, '');
  if (digits.length === 8) return digits;
  return null;
}

function classifyProductGroup(ncmCode) {
  if (!ncmCode) return 'unknown';
  if (GREEN_CODES.has(ncmCode) || /^090111|^090112/.test(ncmCode)) return 'green';
  if (ROASTED_CODES.has(ncmCode) || /^090121|^090122/.test(ncmCode)) return 'roasted';
  if (SOLUBLE_CODES.has(ncmCode) || /^210111|^210112/.test(ncmCode)) return 'soluble';
  return 'unknown';
}

function buildEmptyMetricBucket() {
  return {
    fob_usd: 0,
    kg: 0,
    statistic_qty: 0,
  };
}

function getMetricBucket(container, key) {
  if (!container[key]) container[key] = buildEmptyMetricBucket();
  return container[key];
}

function addMetrics(bucket, row) {
  bucket.fob_usd += row.metric_fob_usd || 0;
  bucket.kg += row.metric_kg || 0;
  bucket.statistic_qty += row.metric_statistic || 0;
}

function finalizeBucket(bucket, totalFob, totalKg) {
  return {
    fob_usd: round(bucket.fob_usd, 2),
    kg: round(bucket.kg, 2),
    statistic_qty: round(bucket.statistic_qty, 2),
    share_fob_pct: sharePct(bucket.fob_usd, totalFob, 4),
    share_kg_pct: sharePct(bucket.kg, totalKg, 4),
  };
}

function avgPrice(fob, kg) {
  if (fob === null || kg === null || kg === 0) return null;
  return round(fob / kg, 6);
}

function sortPeriods(a, b) {
  return a.localeCompare(b);
}

function dedupeRows(rows, makeKey) {
  const seen = new Set();
  const output = [];
  for (const row of rows) {
    const key = makeKey(row);
    if (seen.has(key)) continue;
    seen.add(key);
    output.push(row);
  }
  return output;
}

function normalizeRow(row, kind) {
  const year = Number(row.year);
  const month = Number(row.monthNumber || meta.latest_available_month);
  if (!Number.isInteger(year) || !Number.isInteger(month)) return null;
  const period = year + '-' + pad(month);
  const ncmCode = extractNcmCode(row.coNcm || row.ncmCode || row.ncm || '');

  return {
    kind,
    year,
    month,
    period,
    state: normalizeText(row.federativeUnit || row.state || row.stateName || ''),
    state_key: normalizeStateKey(row.federativeUnit || row.state || row.stateName || ''),
    country: normalizeText(row.country || row.countryName || ''),
    via: normalizeText(row.via || row.transportMode || ''),
    ncm_raw: normalizeText(row.coNcm || row.ncm || row.ncmCode || ''),
    ncm_code: ncmCode,
    product_group: classifyProductGroup(ncmCode),
    metric_fob_usd: toNumber(row.metricFOB, 2) || 0,
    metric_kg: toNumber(row.metricKG, 2) || 0,
    metric_statistic: toNumber(row.metricStatistic, 2) || 0,
  };
}

const rawStateRows = dedupeRows(
  stateResponses
    .flatMap((response) => extractRows(response))
    .map((row) => normalizeRow(row, 'state_country'))
    .filter(Boolean),
  (row) => [row.period, row.state_key, row.country, row.ncm_code, row.metric_fob_usd, row.metric_kg, row.metric_statistic].join('|'),
);

const rawPortRows = dedupeRows(
  transportResponses
    .flatMap((response) => extractRows(response))
    .map((row) => normalizeRow(row, 'transport'))
    .filter(Boolean),
  (row) => [row.period, row.via, row.ncm_code, row.metric_fob_usd, row.metric_kg, row.metric_statistic].join('|'),
);

if (!rawStateRows.length) {
  const debugCounts = stateResponses.map((response, index) => `resp${index}:${extractRows(response).length}`).join(',');
  throw new Error(`Comex State Series empty. details=${JSON.stringify(meta.state_country_current_request ? meta.state_country_current_request.details : [])} responses=${debugCounts}`);
}

const periodMap = new Map();
for (const row of rawStateRows) {
  const periodEntry = periodMap.get(row.period) || {
    period: row.period,
    year: row.year,
    month: row.month,
    total_exports_fob_usd: 0,
    total_exports_kg: 0,
    total_exports_statistic_qty: 0,
    by_group: {},
    by_state: new Map(),
  };

  periodEntry.total_exports_fob_usd += row.metric_fob_usd;
  periodEntry.total_exports_kg += row.metric_kg;
  periodEntry.total_exports_statistic_qty += row.metric_statistic;
  addMetrics(getMetricBucket(periodEntry.by_group, row.product_group), row);

  if (row.state_key) {
    const stateEntry = periodEntry.by_state.get(row.state_key) || {
      state: row.state,
      bucket: buildEmptyMetricBucket(),
    };
    addMetrics(stateEntry.bucket, row);
    periodEntry.by_state.set(row.state_key, stateEntry);
  }

  periodMap.set(row.period, periodEntry);
}

const allPeriods = Array.from(periodMap.keys()).sort(sortPeriods);
const analysisPeriods = allPeriods.slice(-LOOKBACK_MONTHS);
if (!analysisPeriods.length) {
  throw new Error('Comex parser could not find any usable period in state series');
}

const analysisPeriodSet = new Set(analysisPeriods);
const latestPeriod = analysisPeriods[analysisPeriods.length - 1];
const previousPeriod = analysisPeriods.length > 1 ? analysisPeriods[analysisPeriods.length - 2] : shiftPeriod(latestPeriod, -1);
const yoyPeriod = shiftPeriod(latestPeriod, -12);

const latestAgg = periodMap.get(latestPeriod) || null;
const previousAgg = previousPeriod ? periodMap.get(previousPeriod) || null : null;
const yoyAgg = yoyPeriod ? periodMap.get(yoyPeriod) || null : null;

if (!latestAgg) throw new Error('Comex parser could not find latest period in state series');

function finalizePeriod(entry) {
  if (!entry) return null;
  const productMix = {
    green: finalizeBucket(getMetricBucket(entry.by_group, 'green'), entry.total_exports_fob_usd, entry.total_exports_kg),
    roasted: finalizeBucket(getMetricBucket(entry.by_group, 'roasted'), entry.total_exports_fob_usd, entry.total_exports_kg),
    soluble: finalizeBucket(getMetricBucket(entry.by_group, 'soluble'), entry.total_exports_fob_usd, entry.total_exports_kg),
    unknown: finalizeBucket(getMetricBucket(entry.by_group, 'unknown'), entry.total_exports_fob_usd, entry.total_exports_kg),
  };

  return {
    period: entry.period,
    total_exports_fob_usd: round(entry.total_exports_fob_usd, 2),
    total_exports_kg: round(entry.total_exports_kg, 2),
    total_exports_statistic_qty: round(entry.total_exports_statistic_qty, 2),
    avg_fob_usd_per_kg: avgPrice(entry.total_exports_fob_usd, entry.total_exports_kg),
    product_mix: productMix,
  };
}

const latestFinal = finalizePeriod(latestAgg);
const previousFinal = finalizePeriod(previousAgg);
const yoyFinal = finalizePeriod(yoyAgg);

const analysisTotalFob = analysisPeriods.reduce((sum, period) => sum + ((periodMap.get(period) || {}).total_exports_fob_usd || 0), 0);
const analysisTotalKg = analysisPeriods.reduce((sum, period) => sum + ((periodMap.get(period) || {}).total_exports_kg || 0), 0);

// Top 3 Brazilian states over the analysis window
const stateTotals = new Map();
for (const row of rawStateRows) {
  if (!analysisPeriodSet.has(row.period) || !row.state_key) continue;
  const stateEntry = stateTotals.get(row.state_key) || {
    key: row.state_key,
    state: row.state || 'Unknown',
    bucket: buildEmptyMetricBucket(),
  };
  addMetrics(stateEntry.bucket, row);
  stateTotals.set(row.state_key, stateEntry);
}

let top3States = Array.from(stateTotals.values())
  .sort((a, b) => (b.bucket.fob_usd || 0) - (a.bucket.fob_usd || 0))
  .slice(0, 3)
  .map((entry) => ({
    key: entry.key,
    state: entry.state,
    fob_usd: round(entry.bucket.fob_usd, 2),
    kg: round(entry.bucket.kg, 2),
    statistic_qty: round(entry.bucket.statistic_qty, 2),
    share_fob_pct: sharePct(entry.bucket.fob_usd, analysisTotalFob, 4),
    share_kg_pct: sharePct(entry.bucket.kg, analysisTotalKg, 4),
  }));

if (!top3States.length) {
  top3States = Array.from(latestAgg.by_state.entries())
    .map(([key, entry]) => ({
      key,
      state: entry.state || 'Unknown',
      fob_usd: round(entry.bucket.fob_usd, 2),
      kg: round(entry.bucket.kg, 2),
      statistic_qty: round(entry.bucket.statistic_qty, 2),
      share_fob_pct: sharePct(entry.bucket.fob_usd, latestAgg.total_exports_fob_usd, 4),
      share_kg_pct: sharePct(entry.bucket.kg, latestAgg.total_exports_kg, 4),
    }))
    .sort((a, b) => (b.fob_usd || 0) - (a.fob_usd || 0))
    .slice(0, 3);
}

const focusStates = top3States.map((stateRef) => {
  const stateEntry = latestAgg.by_state.get(stateRef.key);
  const bucket = stateEntry ? stateEntry.bucket : buildEmptyMetricBucket();
  return {
    state: stateRef.state,
    fob_usd: round(bucket.fob_usd, 2),
    kg: round(bucket.kg, 2),
    statistic_qty: round(bucket.statistic_qty, 2),
    share_fob_pct: sharePct(bucket.fob_usd, latestAgg.total_exports_fob_usd, 4),
    share_kg_pct: sharePct(bucket.kg, latestAgg.total_exports_kg, 4),
  };
});

const stateSeriesTop3 = analysisPeriods.map((period) => {
  const periodEntry = periodMap.get(period);
  const states = top3States.map((stateRef) => {
    const stateEntry = periodEntry && periodEntry.by_state ? periodEntry.by_state.get(stateRef.key) : null;
    const bucket = stateEntry ? stateEntry.bucket : buildEmptyMetricBucket();
    return {
      state: stateRef.state,
      fob_usd: round(bucket.fob_usd, 2),
      kg: round(bucket.kg, 2),
      statistic_qty: round(bucket.statistic_qty, 2),
      share_fob_pct: sharePct(bucket.fob_usd, periodEntry ? periodEntry.total_exports_fob_usd : 0, 4),
      share_kg_pct: sharePct(bucket.kg, periodEntry ? periodEntry.total_exports_kg : 0, 4),
    };
  });
  return {
    period,
    total_fob_usd: round(periodEntry ? periodEntry.total_exports_fob_usd : 0, 2),
    total_kg: round(periodEntry ? periodEntry.total_exports_kg : 0, 2),
    states,
  };
});

const focusStatesFobTotal = focusStates.reduce((sum, row) => sum + (row.fob_usd || 0), 0);
const focusStatesKgTotal = focusStates.reduce((sum, row) => sum + (row.kg || 0), 0);

// Top 10 destination countries over the analysis window
const destinationTotals = new Map();
for (const row of rawStateRows) {
  if (!analysisPeriodSet.has(row.period)) continue;
  const key = row.country || 'Unknown';
  const destination = destinationTotals.get(key) || {
    country: key,
    bucket: buildEmptyMetricBucket(),
  };
  addMetrics(destination.bucket, row);
  destinationTotals.set(key, destination);
}

const topDestinations = Array.from(destinationTotals.values())
  .map((entry) => ({
    country: entry.country,
    fob_usd: round(entry.bucket.fob_usd, 2),
    kg: round(entry.bucket.kg, 2),
    statistic_qty: round(entry.bucket.statistic_qty, 2),
    share_fob_pct: sharePct(entry.bucket.fob_usd, analysisTotalFob, 4),
    share_kg_pct: sharePct(entry.bucket.kg, analysisTotalKg, 4),
  }))
  .sort((a, b) => (b.fob_usd || 0) - (a.fob_usd || 0))
  .slice(0, 10);

const topDestinationCountries = topDestinations.map((entry) => entry.country);
const topDestinationCountrySet = new Set(topDestinationCountries);

const destinationsSeries = analysisPeriods.map((period) => {
  const periodRows = rawStateRows.filter((row) => row.period === period && row.country);
  const periodFob = periodRows.reduce((sum, row) => sum + row.metric_fob_usd, 0);
  const periodKg = periodRows.reduce((sum, row) => sum + row.metric_kg, 0);

  const cMap = new Map();
  for (const row of periodRows) {
    if (!topDestinationCountrySet.has(row.country)) continue;
    const countryEntry = cMap.get(row.country) || {
      country: row.country,
      bucket: buildEmptyMetricBucket(),
    };
    addMetrics(countryEntry.bucket, row);
    cMap.set(row.country, countryEntry);
  }

  const topCountries = topDestinationCountries.map((country) => {
    const entry = cMap.get(country);
    const bucket = entry ? entry.bucket : buildEmptyMetricBucket();
    return {
      country,
      fob_usd: round(bucket.fob_usd, 2),
      kg: round(bucket.kg, 2),
      share_fob_pct: sharePct(bucket.fob_usd, periodFob, 4),
      share_kg_pct: sharePct(bucket.kg, periodKg, 4),
    };
  });

  return {
    period,
    total_fob_usd: round(periodFob, 2),
    total_kg: round(periodKg, 2),
    top_countries: topCountries,
  };
});

// Transport modes (via) over the analysis window
const transportSeries = analysisPeriods.map((period) => {
  const periodRows = rawPortRows.filter((row) => row.period === period);
  const periodFob = periodRows.reduce((sum, row) => sum + row.metric_fob_usd, 0);
  const periodKg = periodRows.reduce((sum, row) => sum + row.metric_kg, 0);

  const viaMap = new Map();
  for (const row of periodRows) {
    const key = row.via || 'Unknown';
    const viaEntry = viaMap.get(key) || { via: key, bucket: buildEmptyMetricBucket() };
    addMetrics(viaEntry.bucket, row);
    viaMap.set(key, viaEntry);
  }

  const breakdown = Array.from(viaMap.values())
    .map((entry) => ({
      via: entry.via,
      fob_usd: round(entry.bucket.fob_usd, 2),
      kg: round(entry.bucket.kg, 2),
      share_fob_pct: sharePct(entry.bucket.fob_usd, periodFob, 4),
      share_kg_pct: sharePct(entry.bucket.kg, periodKg, 4),
    }))
    .sort((a, b) => (b.fob_usd || 0) - (a.fob_usd || 0));

  return {
    period,
    total_fob_usd: round(periodFob, 2),
    total_kg: round(periodKg, 2),
    breakdown,
  };
});

const latestTransportBreakdown = transportSeries.find((entry) => entry.period === latestPeriod)?.breakdown || [];
const transportModesLatest = latestTransportBreakdown.slice(0, 10);
const topPorts = transportModesLatest.map((entry) => ({
  port: entry.via,
  fob_usd: entry.fob_usd,
  kg: entry.kg,
  share_fob_pct: entry.share_fob_pct,
  share_kg_pct: entry.share_kg_pct,
}));
const portDataAvailable = topPorts.length > 0;

const recentSeries = analysisPeriods.map((period) => {
  const entry = periodMap.get(period);
  const finalized = finalizePeriod(entry);
  return {
    period: finalized.period,
    total_exports_fob_usd: finalized.total_exports_fob_usd,
    total_exports_kg: finalized.total_exports_kg,
    total_exports_statistic_qty: finalized.total_exports_statistic_qty,
    avg_fob_usd_per_kg: finalized.avg_fob_usd_per_kg,
    green_share_kg_pct: finalized.product_mix.green.share_kg_pct,
    roasted_share_kg_pct: finalized.product_mix.roasted.share_kg_pct,
